import {
  ApplicationConfig,
  provideBrowserGlobalErrorListeners,
  provideZoneChangeDetection,
} from '@angular/core';
import { provideRouter } from '@angular/router';
import { provideHttpClient } from '@angular/common/http';

import { routes } from './app.routes';

export const appConfig: ApplicationConfig = {
  providers: [
    provideBrowserGlobalErrorListeners(),
    provideZoneChangeDetection({ eventCoalescing: true }),
    provideRouter(routes),
    provideHttpClient(),
  ],
};

import { Component, inject, signal, toSignal } from '@angular/core';
import { CurrencyPipe } from '@angular/common';
import { ProductService } from './product.service';

@Component({
  selector: 'app-root',
  templateUrl: './app.html',
  styleUrl: './app.css',
  imports: [CurrencyPipe],
})
export class App {
  private readonly productService = inject(ProductService);

  readonly product = toSignal(this.productService.getProduct(), {
    initialValue: null,
  });
}

export interface Product {
  id: number;
  name: string;
  description: string;
  price: number;
  image: string;
}

import { inject, Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Product } from './product.model';
import { Observable } from 'rxjs';

@Injectable({
  providedIn: 'root',
})
export class ProductService {
  private readonly http = inject(HttpClient);
  private readonly apiUrl = 'https://storage.googleapis.com/lowgular-platform/mocks/product.json';

  getProduct(): Observable<Product> {
    return this.http.get<Product>(this.apiUrl);
  }
}

